// ✅ SECURE IMPLEMENTATION
const SecureDataAccess = require('./services/secureDataAccess');
const immutableAuditService = require('./services/immutableAuditService');

async function getPatientData(patientId, practiceId, userId) {
  try {
    // Validate inputs
    if (!patientId || !practiceId || !userId) {
      throw new ValidationError('Missing required parameters');
    }

    // Log access attempt
    await immutableAuditService.addAuditEntry({
      action: 'PATIENT_ACCESS',
      userId,
      patientId,
      practiceId,
      timestamp: new Date()
    });

    // Secure query with field restriction
    const patient = await SecureDataAccess.query('patients', 
      { _id: patientId, practiceId },
      { 
        fields: ['name', 'dateOfBirth', 'medicalHistory'],
        excludeFields: ['ssn', 'insurance.policyNumber']
      }
    );

    if (!patient) {
      throw new NotFoundError('Patient not found');
    }

    return patient;
  } catch (error) {
    // Log error securely
    await immutableAuditService.addAuditEntry({
      action: 'PATIENT_ACCESS_ERROR',
      error: error.message,
      userId,
      patientId
    });

    // Return sanitized error
    throw new SecureError('Unable to retrieve patient data');
  }
}

