// ✅ SECURE API ENDPOINT
const express = require('express');
const authMiddleware = require('./middleware/auth');
const rateLimiter = require('./middleware/rateLimiter');
const validator = require('./utils/validator');
const SecureDataAccess = require('./services/secureDataAccess');

router.post('/api/patients',
  authMiddleware.requireAuth,
  authMiddleware.requireRole(['doctor', 'admin']),
  rateLimiter.limit({ requests: 10, per: 'minute' }),
  async (req, res) => {
    try {
      // Validate and sanitize input
      const sanitizedData = validator.sanitize(req.body, {
        name: { type: 'string', required: true, maxLength: 100 },
        dateOfBirth: { type: 'date', required: true },
        email: { type: 'email', required: false }
      });

      // Add practice context
      sanitizedData.practiceId = req.user.practiceId;
      sanitizedData.createdBy = req.user.id;

      // Create with secure service
      const patient = await SecureDataAccess.create('patients', sanitizedData);

      // Log creation
      await immutableAuditService.addAuditEntry({
        action: 'PATIENT_CREATED',
        userId: req.user.id,
        patientId: patient._id,
        practiceId: req.user.practiceId
      });

      // Return sanitized response
      res.status(201).json({
        success: true,
        data: {
          id: patient._id,
          name: patient.name
        }
      });
    } catch (error) {
      // Handle error securely
      const safeError = errorHandler.handle(error);
      res.status(safeError.status).json({
        success: false,
        error: safeError.message
      });
    }
  }
);
